#include <bits/stdc++.h>
using namespace std;

void examples(int n) {
    // --- O(n): single linear loop ---
    for (int i = 0; i < n; i++) { /* body */ }          // n iterations

    // --- O(log n): halving step ---
    for (int i = n; i >= 1; i /= 2) { /* body */ }     // log2(n) iterations

    // --- O(n^2): nested linear loops ---
    for (int i = 0; i < n; i++)
        for (int j = 0; j < n; j++) { /* body */ }      // n*n iterations

    // --- O(n^2) again: triangle loop (n*(n-1)/2) ---
    for (int i = 0; i < n; i++)
        for (int j = i+1; j < n; j++) { /* body */ }    // still O(n^2)

    // --- O(n log n): outer linear, inner logarithmic ---
    for (int i = 0; i < n; i++)
        for (int j = 1; j < n; j *= 2) { /* body */ }  // n * log n

    // --- O(n sqrt(n)): outer linear, inner sqrt ---
    for (int i = 1; i <= n; i++)
        for (int j = 1; (long long)j*j <= i; j++) { }   // sum of sqrt(i) ≈ n*sqrt(n)

    // --- O(sqrt(n)): trial division ---
    for (int i = 2; (long long)i*i <= n; i++) { }       // sqrt(n) iterations

    // --- O(n): two-pointer (both pointers move at most n steps total) ---
    int lo = 0, hi = 0;
    while (hi < n) {
        hi++;                   // hi moves forward at most n times total
        while (lo < hi) lo++;   // lo moves forward at most n times total
    }                           // combined: O(n), NOT O(n^2)
}

int main() {
    // O(n log n): sorting
    int n = 100000;
    vector<int> v(n);
    sort(v.begin(), v.end()); // O(n log n)

    // O(n log n): n binary searches
    for (int i = 0; i < n; i++)
        lower_bound(v.begin(), v.end(), i); // O(log n) each

    return 0;
}

#include <bits/stdc++.h>
using namespace std;

// Merge sort: T(n) = 2T(n/2) + O(n) => O(n log n)
void mergeSort(vector<int>& a, int l, int r) {
    if (l >= r) return;
    int mid = (l + r) / 2;
    mergeSort(a, l, mid);       // T(n/2)
    mergeSort(a, mid+1, r);     // T(n/2)
    inplace_merge(a.begin()+l, a.begin()+mid+1, a.begin()+r+1); // O(n) merge
}

// Binary search: T(n) = T(n/2) + O(1) => O(log n)
bool bsearch(vector<int>& a, int lo, int hi, int t) {
    if (lo > hi) return false;
    int mid = lo + (hi-lo)/2;
    if (a[mid] == t) return true;
    if (a[mid] < t) return bsearch(a, mid+1, hi, t); // T(n/2)
    return bsearch(a, lo, mid-1, t);                  // T(n/2)
}
// Each call does O(1) work then recurses on half the input => O(log n)

// Careful: this LOOKS like O(n log n) but is actually O(n^2) !
void badSort(vector<int>& a, int n) {
    if (n <= 1) return;
    // find max and put at end: O(n)
    int mx = max_element(a.begin(), a.begin()+n) - a.begin();
    swap(a[mx], a[n-1]);
    badSort(a, n-1);  // T(n-1), NOT T(n/2)
}   // T(n) = T(n-1) + O(n) => O(n^2) — this is just selection sort!

