#include <bits/stdc++.h>
using namespace std;

// Demonstrate that n push_backs cost O(n) total, not O(n^2)
// Capacity doubles: 1 -> 2 -> 4 -> 8 -> ... -> n
// Total copy operations: 1 + 2 + 4 + ... + n/2 < 2n => O(n)
void amortizedDemo(int n) {
    vector<int> v;
    long long totalCopies = 0;
    int cap = 1;
    for (int i = 0; i < n; i++) {
        if ((int)v.size() == cap) {
            totalCopies += cap; // all elements copied on resize
            cap *= 2;
        }
        v.push_back(i);
    }
    cout << "n = " << n << ", total copies = " << totalCopies << "\n";
    // Always < 2n regardless of n
}

// Another amortized example: monotone stack
// Each element is pushed and popped at most once => O(n) total
void nextGreater(vector<int>& arr) {
    int n = arr.size();
    vector<int> ans(n, -1);
    stack<int> st; // stores indices
    for (int i = 0; i < n; i++) {
        // Each element pushed once, popped at most once => O(n) total
        while (!st.empty() && arr[st.top()] < arr[i]) {
            ans[st.top()] = arr[i];
            st.pop();
        }
        st.push(i);
    }
    for (int x : ans) cout << x << " ";
    cout << "\n";
}

int main() {
    amortizedDemo(1000000); // prints ~2000000 (< 2n)
    vector<int> a = {4, 5, 2, 10, 8};
    nextGreater(a); // 5 10 10 -1 -1
    return 0;
}

