#include <bits/stdc++.h>
using namespace std;

int main() {
    long long n = 200000;
    long long budget = 2e8; // 2 seconds at 10^8 ops/sec

    // Solution A: O(n^2)
    long long opsA = n * n;
    cout << "A: " << opsA << " ops => " << (opsA <= budget ? "AC" : "TLE") << "\n";
    // 4 * 10^10 => TLE

    // Solution B: O((n+q) log n), q = n
    long long opsB = 2 * n * (long long)log2(n);
    cout << "B: " << opsB << " ops => " << (opsB <= budget ? "AC" : "TLE") << "\n";
    // ~2 * 200000 * 17.6 ≈ 7 * 10^6 => AC

    // Solution C: O(n * sqrt(n))
    long long opsC = n * (long long)sqrt((double)n);
    cout << "C: " << opsC << " ops => " << (opsC <= budget ? "AC" : "TLE") << "\n";
    // 200000 * 447 ≈ 8.9 * 10^7 => AC (borderline, but within budget)

    return 0;
}

