// Count the number of pairs (i, j) with i < j in array arr such that
// arr[j] - arr[i] == K (exactly).
// Naive O(n^2): check all pairs. n can be up to 10^5, K up to 10^9.
// Your task: implement the O(n log n) version using sorting + binary search.

sections.solution:
#include <bits/stdc++.h>
using namespace std;

int main() {
    ios_base::sync_with_stdio(false);
    cin.tie(NULL);

    int n;
    long long k;
    cin >> n >> k;
    vector<long long> arr(n);
    for (auto& x : arr) cin >> x;

    // Approach: sort + count pairs using frequency (order-independent)
    // After sorting, for each unique value v, count occurrences of v+k.
    // Pair (v, v+k) is always an original pair since v < v+k (if k > 0).
    sort(arr.begin(), arr.end());

    long long ans = 0;
    if (k == 0) {
        // Special case: count pairs of equal elements
        int i = 0;
        while (i < n) {
            int j = i;
            while (j < n && arr[j] == arr[i]) j++;
            long long cnt = j - i;
            ans += cnt * (cnt - 1) / 2;
            i = j;
        }
    } else {
        // For each element, count occurrences of element + k
        for (int i = 0; i < n; i++) {
            long long target = arr[i] + k;
            ans += upper_bound(arr.begin(), arr.end(), target)
                 - lower_bound(arr.begin(), arr.end(), target);
        }
        // Divide by 2 only if k allows both orderings — but since k > 0,
        // arr[i] < arr[i]+k, so every pair is counted exactly once
        // (once when we process the smaller element).
        // However, we're counting ALL occurrences of target including at i itself.
        // Since k > 0, arr[i] != arr[i]+k, so no self-pairing occurs.
        // But we may double-count: pair (a, a+k) counted once for element a
        // and once for element a+k (looking for a+k+k=a+2k, not a).
        // So NO double count. Answer is correct.
    }
    cout << ans << "\n";
    return 0;
}
